device_buffer generate_u32(int size) {
  std::vector<uint32_t> values(size);
  std::generate(values.begin(), values.end(), std::rand);
  device_buffer result(size, ValueType::U32());
  cudaCheck(cudaMemcpy(result.data(), values.data(), size * sizeof(uint32_t),
                       cudaMemcpyHostToDevice));
  return result;
}

device_vec<MinMaxProbProvenance::Tag> generate_tags(int size) {
  std::vector<MinMaxProbProvenance::Tag> tags(size);
  std::generate(tags.begin(), tags.end(), std::rand);
  return device_vec<MinMaxProbProvenance::Tag>(tags);
}

TEST_CASE("scratch", "") {
  auto t1 = TupleType(std::vector{TupleType(ValueType::U32())});
  auto t2 = TupleType({ValueType::U32()});
  std::cout << "t1\n" << t1 << std::endl;
  std::cout << "t2\n" << t2 << std::endl;
  REQUIRE(false);
}

struct CustomLess {
  template <typename DataType>
  __device__ bool operator()(const DataType &lhs, const DataType &rhs) {
    return lhs < rhs;
  }
};

struct Tup {
