#include "dat.cu"

__global__ void copy_tups(char *dest0, uint32_t *dest1, uint32_t *dest2,
                          float *dest3, Tup *source, size_t size) {
  size_t index = (blockIdx.x * blockDim.x) + threadIdx.x;
  if (index >= size) {
    return;
  }

  dest0[index] = source[index].a;
  dest1[index] = source[index].b;
  dest2[index] = source[index].c;
  dest3[index] = source[index].d;
}

struct Decomposer {
  template <typename T>
  __host__ __device__ ::cuda::std::tuple<char &, uint32_t &, uint32_t &>
  operator()(
      // thrust::tuple<char, uint32_t, uint32_t> &key
      // thrust::detail::tuple_of_iterator_references<char &, uint32_t &,
      // uint32_t &> &key
      T &key) const {
    thrust::detail::tuple_of_iterator_references<char &, uint32_t &, uint32_t &>
        &t = key;
    return ::cuda::std::tuple<char &, uint32_t &, uint32_t &>(
        thrust::get<0>(key), thrust::get<1>(key), thrust::get<2>(key));
  }
};
struct IdDecomposer {
  template <typename... T>
  __host__ __device__ ::cuda::std::tuple<T &...> operator()(
      // thrust::tuple<char, uint32_t, uint32_t> &key
      // thrust::detail::tuple_of_iterator_references<char &, uint32_t &,
      // uint32_t &> &key
      cuda::std::tuple<T...> &key) const {
    return key;
  }
};

template <typename T, int Index>
struct Pair {
  using type = T;
  static constexpr int index = Index;
};

template <typename... P>
__global__ void compact(
    thrust::zip_iterator<thrust::tuple<typename P::type *...>> in,
    cuda::std::tuple<typename P::type...> *out, size_t size, Product<P...>) {
  size_t row = (blockIdx.x * blockDim.x) + threadIdx.x;
  if (row >= size) {
    return;
  }

  SINK(
      (cuda::std::get<P::index>(out[row]) = thrust::get<P::index>(in[row]))...);
}

struct Point {
  float x, y;
};
struct PointDecomposer {
  __host__ __device__ ::cuda::std::tuple<float &, float &> operator()(
      Point &p) const {
    return ::cuda::std::tuple<float &, float &>(p.x, p.y);
  }
};
struct decomposer_t {
  __host__ __device__ ::cuda::std::tuple<char &, uint32_t &, uint32_t &>
  operator()(cuda::std::tuple<char, uint32_t, uint32_t> &p) const {
    return ::cuda::std::tuple<char &, uint32_t &, uint32_t &>(
        cuda::std::get<0>(p), cuda::std::get<1>(p), cuda::std::get<2>(p));
  }
};

TEST_CASE("sort", "") {
  using Prov = MinMaxProbProvenance;
  auto size = sizeof(tups) / sizeof(tups[0]);
  device_vec<Tup> tups_d(size);
  cudaCheck(cudaMemcpy(tups_d.data(), tups, size * sizeof(Tup),
                       cudaMemcpyHostToDevice));

  device_vec<char> sample_d(size);
  device_vec<uint32_t> col0_d(size);
  device_vec<uint32_t> col1_d(size);
  device_vec<float> col2_d(size);
  copy_tups<<<ROUND_UP_TO_NEAREST(size, 512), 512>>>(
      sample_d.data(), col0_d.data(), col1_d.data(), col2_d.data(),
      tups_d.data(), size);

  auto it = thrust::make_zip_iterator(thrust::make_tuple(
      sample_d.data(), col0_d.data(), col1_d.data()
      // col2_d.data()
      ));

  device_vec<char> out0(size);
  device_vec<uint32_t> out1(size);
  device_vec<uint32_t> out2(size);
  auto output = thrust::make_zip_iterator(
      thrust::make_tuple(out0.data(), out1.data(), out2.data()));

  thrust::default_random_engine g(1);
  thrust::shuffle(thrust::device, it, it + size, g);

  BENCHMARK("MegeSort") {
    std::size_t temp_storage_bytes = 0;
    void *d_temp_storage = nullptr;
    CustomLess op;
    cub::DeviceMergeSort::SortKeys(d_temp_storage, temp_storage_bytes, it, size,
                                   op);
    device_vec<char> v(temp_storage_bytes);
    d_temp_storage = v.data();
    return cub::DeviceMergeSort::SortKeys(d_temp_storage, temp_storage_bytes,
                                          it, size, op);
  };

  BENCHMARK("RadixSort") {
    std::size_t temp_storage_bytes = 0;
    void *d_temp_storage = nullptr;
    auto tmp = it[0];
    decomposer_t decomposer;

    device_vec<cuda::std::tuple<char, uint32_t, uint32_t>> compacted(size);
    compact<<<ROUND_UP_TO_NEAREST(size, 128), 128>>>(
        it, compacted.data(), size,
        Product<Pair<char, 0>, Pair<uint32_t, 1>, Pair<uint32_t, 2>>{});

    device_vec<cuda::std::tuple<char, uint32_t, uint32_t>> result(size);

    cub::DeviceRadixSort::SortKeys(d_temp_storage, temp_storage_bytes,
                                   compacted.data(), result.data(), size,
                                   decomposer);
    device_vec<char> v(temp_storage_bytes);
    d_temp_storage = v.data();
    return cub::DeviceRadixSort::SortKeys(d_temp_storage, temp_storage_bytes,
                                   compacted.data(), result.data(), size,
                                   decomposer);
  };

  // auto sorted_until = thrust::is_sorted_until(thrust::device, it, it + size);
  // auto sorted_len = thrust::distance(it, sorted_until);
  // std::cout << "Sorted until " << sorted_len << " for size " << size <<
  // std::endl; thrust::sort(thrust::device, it, it + size); sorted_until =
  // thrust::is_sorted_until(thrust::device, it, it + size); sorted_len =
  // thrust::distance(it, sorted_until); std::cout << "Sorted until " <<
  // sorted_len << " for size " << size << std::endl; REQUIRE(sorted_len ==
  // size);
  REQUIRE(false);
}
